#!/bin/bash
# Read a full message from work-buddy's messaging service.
# This script is auto-generated by check_messages.sh on session start.
# Session ID is pre-configured for read tracking.

SERVICE_URL="%%SERVICE_URL%%"
SESSION="%%SESSION%%"
READER_PROJECT="%%SENDER%%"

usage() {
    cat <<'HELP'
Usage: bash /tmp/wb/read [OPTIONS]

Read the full content of a message from work-buddy's messaging service.
Automatically marks the message as read by your session.

Required:
  --id <message-id>      ID of the message to read (shown in message summaries)

Optional:
  --help                 Show this help message

Examples:
  bash /tmp/wb/read --id 20260403T044932-work-buddy-c8ea288b
HELP
    exit 0
}

# Parse arguments
MSG_ID=""

while [ $# -gt 0 ]; do
    case "$1" in
        --id)       MSG_ID="$2"; shift 2 ;;
        --help|-h)  usage ;;
        *)          echo "Unknown option: $1. Use --help for usage."; exit 1 ;;
    esac
done

# Validate required args
if [ -z "$MSG_ID" ]; then echo "Error: --id is required. Use --help for usage."; exit 1; fi

# Fetch and format in one pipe to preserve UTF-8
curl -s "$SERVICE_URL/messages/$MSG_ID?session=$SESSION&reader_project=$READER_PROJECT" 2>/dev/null | python -c "
import sys, json
try:
    m = json.load(sys.stdin)
    if 'error' in m:
        print(f'Error: {m[\"error\"]}')
        sys.exit(1)
    print(f'From: {m[\"sender\"]}')
    print(f'To: {m[\"recipient\"]}')
    print(f'Subject: {m[\"subject\"]}')
    print(f'Type: {m[\"type\"]} | Priority: {m[\"priority\"]} | Status: {m[\"status\"]}')
    print(f'Date: {m[\"created_at\"]}')
    if m.get('thread_id'):
        print(f'Thread: {m[\"thread_id\"]}')
    if m.get('in_reply_to'):
        print(f'In reply to: {m[\"in_reply_to\"]}')
    print(f'ID: {m[\"id\"]}')
    print()
    if m.get('body'):
        print(m['body'])
    else:
        print('(no body)')
except json.JSONDecodeError:
    print('Error: No response from messaging service. Is it running?')
    sys.exit(1)
"
